查询表空间使用情况表空间总体情况SELECT UPPER(F.TABLESPACE_NAME) &quot;表空间名&quot;,　　D.TOT_GROOTTE_MB &quot;表空间大小(G)&quot;,　　D.TOT_GROOTTE_MB - F.TOTAL_BYTES &quot;已使用空间(G)&quot;,　　--TO_CHAR(ROUND((D.TOT_GROOTTE_MB - F.TOTAL_BYTES) / D.TOT_GROOTTE_MB * 100,2),&#x27;990.99&#x27;) || &#x27;%&#x27; &quot;使用比&quot;,    TO_CHAR(ROUND((D.TOT_GROOTTE_MB - F.TOTAL_BYTES) / D.TOT_GROOTTE_MB * 100,2)) || &#x27;%&#x27; &quot;使用比&quot;,　　F.TOTAL_BYTES &quot;空闲空间(G)&quot;,　　F.MAX_BYTES &quot;最大块(G)&quot;    --,E.file_name &quot;存储位置&quot;　　FROM (SELECT TABLESPACE_NAME,　　ROUND(SUM(BYTES) / (1024 * 1024 * 1024), 2) TOTAL_BYTES,　　ROUND(MAX(BYTES) / (1024 * 1024 * 1024), 2) MAX_BYTES　　FROM SYS.DBA_FREE_SPACE　　GROUP BY TABLESPACE_NAME) F,　　(SELECT DD.TABLESPACE_NAME,　　 ROUND(SUM(DD.BYTES) / (1024 * 1024 * 1024), 2) TOT_GROOTTE_MB　　FROM SYS.DBA_DATA_FILES DD　　GROUP BY DD.TABLESPACE_NAME) D,    SYS.DBA_DATA_FILES E　　WHERE D.TABLESPACE_NAME = F.TABLESPACE_NAME　　ORDER BY 1;

查询表空间的总容量select tablespace_name, sum(bytes) / 1024 / 1024 /1024 as &quot;大小（GB）&quot;　　from dba_data_files　　group by tablespace_name;

查询表空间使用率select total.tablespace_name,　　round(total.MB, 2) as Total_MB,　　round(total.MB - free.MB, 2) as Used_MB,　　round((1 - free.MB / total.MB) * 100, 2) || &#x27;%&#x27; as Used_Pct　　from (select tablespace_name, sum(bytes) / 1024 / 1024 as MB　　from dba_free_space　　group by tablespace_name) free,　　(select tablespace_name, sum(bytes) / 1024 / 1024 as MB　　from dba_data_files　　group by tablespace_name) total　　where free.tablespace_name = total.tablespace_name;

监控当前数据库谁在运行什么SQL语句select osuser, username, sql_text  from  v$session a, v$sqltext b where  a.sql_address =b.address order by address, piece;

找使用CPU多的用户sessionselect a.sid,spid,status,substr(a.program,1,40) prog, a.terminal,osuser,value/60/100 value from  v$session a,v$process b,v$sesstat c where  c.statistic#=12 and         c.sid=a.sid and         a.paddr=b.addr         order by value desc;





等待最多的用户SELECT   s.SID, s.username, SUM (a.wait_time + a.time_waited) total_wait_time    FROM v$active_session_history a, v$session s   WHERE a.sample_time BETWEEN SYSDATE - 30 / 2880    AND SYSDATEGROUP BY s.SID, s.usernameORDER BY total_wait_time DESC;

等待最多的SQLSELECT   a.program, a.session_id, a.user_id, d.username, s.sql_text,         SUM (a.wait_time + a.time_waited) total_wait_time    FROM v$active_session_history a, v$sqlarea s, dba_users d   WHERE a.sample_time BETWEEN SYSDATE - 30 / 2880 AND SYSDATE     AND a.sql_id = s.sql_id     AND a.user_id = d.user_idGROUP BY a.program, a.session_id, a.user_id, s.sql_text, d.username;

查看消耗资源最多的SQLSELECT hash_value, executions, buffer_gets, disk_reads, parse_callsFROM V$SQLAREAWHERE buffer_gets &gt; 10000000 OR disk_reads &gt; 1000000ORDER BY buffer_gets + 100 * disk_reads DESC;

查看某条SQL语句的资源消耗查看某条SQL语句的资源消耗SELECT hash_value, buffer_gets, disk_reads, executions, parse_callsFROM V$SQLAREAWHERE hash_Value = 228801498 AND address = hextoraw(&#x27;CBD8E4B0&#x27;);

查询会话执行的实际SQLSELECT   a.SID, a.username, s.sql_text    FROM v$session a, v$sqltext s   WHERE a.sql_address = s.address     AND a.sql_hash_value = s.hash_value     AND a.status = &#x27;ACTIVE&#x27;ORDER BY a.username, a.SID, s.piece;

查看死锁信息SELECT (SELECT username          FROM v$session         WHERE SID = a.SID) blocker, a.SID, &#x27;is blocking&#x27;,       (SELECT username          FROM v$session         WHERE SID = b.SID) blockee, b.SID  FROM v$lock a, v$lock b WHERE a.BLOCK = 1 AND b.request &gt; 0 AND a.id1 = b.id1 AND a.id2 = b.id2;

